package autostart

import (
    "os"
    "os/user"
    "path/filepath"
)

func Enable(appName string) error {
  execPath, _ := os.Executable()
    usr, err := user.Current()
    if err != nil {
        return err
    }

    autostartDir := filepath.Join(usr.HomeDir, ".config", "autostart")
    err = os.MkdirAll(autostartDir, 0755)
    if err != nil {
        return err
    }

    desktopFile := `[Desktop Entry]
Type=Application
Name=` + appName + `
Exec=` + execPath + `
X-GNOME-Autostart-enabled=true
Terminal=false
`

    filePath := filepath.Join(autostartDir, appName+".desktop")
    return os.WriteFile(filePath, []byte(desktopFile), 0644)
}

func Disable(appName string) error {
    usr, err := user.Current()
    if err != nil {
        return err
    }
    desktopPath := filepath.Join(usr.HomeDir, ".config", "autostart", appName+".desktop")
    return os.Remove(desktopPath)
}

func IsEnabled(appName string) (bool, error) {
    usr, err := user.Current()
    if err != nil {
        return false, err
    }
    desktopPath := filepath.Join(usr.HomeDir, ".config", "autostart", appName+".desktop")
    _, err = os.Stat(desktopPath)
    if os.IsNotExist(err) {
        return false, nil
    }
    return err == nil, err
}

package hwmonitor

import (
    "fmt"
    "os/exec"
    "strconv"
    "strings"
    "time"

    "github.com/shirou/gopsutil/v4/cpu"
    "github.com/shirou/gopsutil/v4/mem"
)

func GetCPUUsage() (float64, error) {
    percentages, err := cpu.Percent(time.Second, false)
    if err != nil || len(percentages) == 0 {
        return 0, err
    }
    return percentages[0], nil
}

func GetMemoryUsage() (float64, error) {
    v, err := mem.VirtualMemory()
    if err != nil {
        return 0, err
    }
    return v.UsedPercent, nil
}

func GetGPUUsage() (float64, error) {
    out, err := exec.Command("nvidia-smi", "--query-gpu=utilization.gpu", "--format=csv,noheader,nounits").Output()
    if err != nil {
        return 0, fmt.Errorf("nvidia-smi не найден или не установлен")
    }
    str := strings.TrimSpace(string(out))
    value, err := strconv.ParseFloat(str, 64)
    if err != nil {
        return 0, fmt.Errorf("не удалось распарсить вывод nvidia-smi: %w", err)
    }
    return value, nil
}

